sql:
SELECT car_type
FROM carriages
WHERE is_active = 1 AND capacity > 50;

SELECT COUNT(*) AS active_carriages
FROM carriages
WHERE is_active = 1;

SELECT MAX(capacity) AS max_capacity
FROM carriages
WHERE is_active = 1;

external_knowledge:
- 'central station' refers to the station with ID = 1; 
- 'spacious' refers to carriages with the highest capacity; 
- 'in service' means carriages with is_active = 1.
